<template>
    <div class="row q-col-gutter-md">
        <div class="col-md-8 col-lg-8 col-sm-8 col-xs-12">
            <div class="row">
                <VuePictureCropper
                    :boxStyle="{
                        width: '100%',
                        height: '100%',
                        backgroundColor: '#f8f8f8',
                        margin: 'auto',
                    }"
                    :img="imageCropper"
                    :options="{
                        viewMode: 1,
                        dragMode: 'crop',
                    }"
                    @crop="imagePreview = cropper.getDataURL()"
                    v-if="imageCropper"
                />
                <q-img :src="defaultImage" fit="fill" v-else />
            </div>
            <div class="col text-center q-pt-md">
                <q-btn icon="upload" @click="fileRef.pickFiles()">
                    <q-tooltip> Subir imagen </q-tooltip>
                </q-btn>
                <q-btn
                    icon="rotate_left"
                    @click="rotateLeft"
                    :disable="!imageCropper"
                >
                    <q-tooltip v-if="imageCropper">
                        Rotar a la izquierda
                    </q-tooltip>
                </q-btn>
                <q-btn
                    icon="rotate_right"
                    @click="rotateRight"
                    :disable="!imageCropper"
                >
                    <q-tooltip v-if="imageCropper">
                        Rotar a la derecha
                    </q-tooltip>
                </q-btn>
                <q-btn
                    icon="settings_backup_restore"
                    @click="resetCropper"
                    :disable="!imageCropper"
                >
                    <q-tooltip v-if="imageCropper"> Restaurar </q-tooltip>
                </q-btn>
                <q-btn
                    icon="save"
                    no-caps
                    @click="finish"
                    :disable="!imageCropper"
                    ><q-tooltip v-if="imageCropper"> Guardar </q-tooltip></q-btn
                >
                <q-btn icon="close" @click="cancel" no-caps
                    ><q-tooltip> Cancelar </q-tooltip></q-btn
                >
            </div>
        </div>
        <div class="col-md-4 col-lg-4 col-sm-4 col-xs-12 self-center">
            <div class="column items-center">
                <q-avatar
                    size="120px"
                    class="shadow-10"
                    v-if="avatar && imageCropper"
                >
                    <img :src="imagePreview" />
                </q-avatar>
                <img
                    :src="imagePreview"
                    style="width: 100%; height: 100%"
                    v-else-if="imageCropper"
                />
                <img
                    :src="defaultImage"
                    style="width: 150px; height: 150px"
                    v-else
                />
            </div>
            <div class="col text-center q-pt-md">vista previa</div>
        </div>
    </div>

    <q-file
        v-model="file"
        ref="fileRef"
        class="hidden"
        accept=".jpg, image/*"
        @update:model-value="handleFile"
    />
</template>

<script setup>
import { ref, onBeforeMount } from "vue";
import VuePictureCropper, { cropper } from "vue-picture-cropper";
defineOptions({
    name: "CropperField",
});

const props = defineProps({
    name: {
        type: String,
        required: true,
    },
    image: String,
    avatar: {
        type: Boolean,
        default: false,
    },
});

const emits = defineEmits(["cancel", "finish"]);
const imageCropper = ref(null);
const imagePreview = ref(null);
const file = ref(null);
const fileRef = ref(null);
const defaultImage =
    "data:image/png;base64,";

onBeforeMount(() => {
    imageCropper.value = props.image;
});

const handleFile = (file) => {
    imageCropper.value = URL.createObjectURL(file);
};

const resetCropper = () => {
    cropper.reset();
};

const rotateLeft = () => {
    cropper.rotate(-90);
};

const rotateRight = () => {
    cropper.rotate(90);
};

const cancel = () => {
    emits("cancel");
};

const finish = () => {
    emits("finish", props.name, imagePreview.value);
};
</script>
